SELECT count(*) FROM title, movie_keyword, cast_info, keyword, kind_type, role_type, name, aka_name, movie_info WHERE movie_keyword.movie_id = title.id AND cast_info.movie_id = title.id AND movie_keyword.keyword_id = keyword.id AND title.kind_id = kind_type.id AND cast_info.role_id = role_type.id AND cast_info.person_id = name.id AND aka_name.person_id = name.id AND movie_info.movie_id = title.id;